class WebSearchAgent:
    def search(self, query):
        if not self.needs_search(query):
            return self.answer_from_knowledge(query)

        search_queries = self.translate_query(query)

        # Parallel workers with different strategies
        workers = [
            Worker(domain='reddit.com'),
            Worker(domain='news'),
            Worker(temporal='last_3_months')
        ]

        results = await asyncio.gather(*[
            w.search(search_queries) for w in workers
        ])

        return self.synthesize_with_citations(results)
